ValidationRule.errorConditionFormula:
AND( CONTAINS($Profile.Name, "CRN"),
/* Mapeia o novo status para um número */ CASE(TEXT(CRNStatus__c), "NOT_STARTED", 1, "DRAFT_IN_PREPARATION", 2, "DRAFT_SENT_UNDER_APPROVAL", 3, "DRAFT_APPROVED", 4, "AWAITING_DD_ACCEPTANCE", 5, "SIGNATURE_SCHEDULED", 6, "DEED_SIGNED", 7, 0 ) <
/* Mapeia o status anterior para um número */ CASE(TEXT(PRIORVALUE(CRNStatus__c)), "NOT_STARTED", 1, "DRAFT_IN_PREPARATION", 2, "DRAFT_SENT_UNDER_APPROVAL", 3, "DRAFT_APPROVED", 4, "AWAITING_DD_ACCEPTANCE", 5, "SIGNATURE_SCHEDULED", 6, "DEED_SIGNED", 7, 0 ) )
